import sys
import re

def drop_cap(s: str) -> str:
    pattern = re.compile(r'\S+')
    def repl(m: re.Match) -> str:
        w = m.group(0)
        if len(w) > 2:
            return w[0].upper() + w[1:].lower()
        return w
    return pattern.sub(repl, s)

def solve() -> None:
    line = sys.stdin.readline()
    if line.endswith('\n'):
        line = line[:-1]
    print(drop_cap(line))

