def decompose_number(n: int) -> str:
    if n == 0:
        return ""
    s = str(n)
    length = len(s)
    terms = []
    for i, ch in enumerate(s):
        digit = ord(ch) - 48  # ord('0') == 48
        if digit == 0:
            continue
        power = 10 ** (length - i - 1)
        if power == 1:
            term = str(digit)
        else:
            term = f"{digit}*{power}"
        terms.append(term)
    return "+".join(terms)


