    result = decompose_number(n_input)
    print(result)

def are_isomorphic(string1: str, string2: str) -> bool:
    """
    Returns True iff a permutation of the alphabet can transform string1 into string2.
    This is equivalent to checking whether the two strings are isomorphic under a
    bijective character mapping.
    """
    if len(string1) != len(string2):
        return False

    forward: dict[str, str] = {}
    backward: dict[str, str] = {}

    for c1, c2 in zip(string1, string2):
        # Forward consistency: same source character must always map to the same target.
        if c1 in forward:
            if forward[c1] != c2:
                return False
        else:
            # Backward consistency: two different source characters cannot map to the same target.
            if c2 in backward and backward[c2] != c1:
                return False
            forward[c1] = c2
            backward[c2] = c1

    return True


def main() -> None:
    """
    Reads two strings from standard input, checks the substitution‑cipher condition,
    and prints the result.
    """
    import sys

    # Read the two lines, stripping the trailing newline characters.
    s1 = sys.stdin.readline().rstrip('\n')
    s2 = sys.stdin.readline().rstrip('\n')

    result = are_isomorphic(s1, s2)

    # Print exactly "True" or "False" (capitalised) as required by the problem statement.
    print(str(result))


if __name__ == "__main__":
    main()

def elevator(left: int, right: int, call: int) -> str:
    dist_left = abs(call - left)
    dist_right = abs(call - right)
    if dist_left < dist_right:
        return "left"
    else:
        return "right"

