def alphabet_war(fight: str) -> str:
    n = len(fight)
    dead = [False] * n

    for i, ch in enumerate(fight):
        if ch == '*':
            dead[i] = True
            if i > 0:
                dead[i - 1] = True
            if i + 1 < n:
                dead[i + 1] = True

    left_score = 0
    right_score = 0
    power = {'w': 4, 'p': 3, 'b': 2, 's': 1,
             'm': 4, 'q': 3, 'd': 2, 'z': 1}
    left_set = {'w', 'p', 'b', 's'}
    right_set = {'m', 'q', 'd', 'z'}

    for i, ch in enumerate(fight):
        if dead[i]:
            continue
        if ch in power:
            if ch in left_set:
                left_score += power[ch]
            else:  # ch in right_set
                right_score += power[ch]

    if left_score > right_score:
        return "Left side wins!"
    elif right_score > left_score:
        return "Right side wins!"
    else:
        return "Let's fight again!"


