import sys
import json
import ast
from typing import List, Any, Tuple, Union


def _as_pair(creature: Any) -> Tuple[int, int]:
    """
    Convert a creature description to a (power, toughness) tuple.
    Accepts:
      * list or tuple of two numbers
      * dict with keys 'power' and 'toughness' (or 'p'/'t')
      * string representation like "[2,3]" or "(2,3)"
    Raises ValueError if the format cannot be interpreted.
    """
    # 1. Already a dict?
    if isinstance(creature, dict):
        try:
            power = int(creature["power"])
            toughness = int(creature["toughness"])
            return power, toughness
        except Exception:
            # allow short keys
            try:
                power = int(creature["p"])
                toughness = int(creature["t"])
                return power, toughness
            except Exception as exc:
                raise ValueError("Dict creature must contain power/toughness") from exc

    # 2. List / tuple
    if isinstance(creature, (list, tuple)):
        if len(creature) != 2:
            raise ValueError("Creature list/tuple must have exactly two elements")
        try:
            return int(creature[0]), int(creature[1])
        except Exception as exc:
            raise ValueError("Power and toughness must be integers") from exc

    # 3. String – try to evaluate safely
    if isinstance(creature, str):
        creature = creature.strip()
        # Remove surrounding brackets if present
        if (creature.startswith("[") and creature.endswith("]")) or (
            creature.startswith("(") and creature.endswith(")")
        ):
            inner = creature[1:-1]
            parts = inner.split(",")
            if len(parts) == 2:
                try:
                    return int(parts[0].strip()), int(parts[1].strip())
                except Exception as exc:
                    raise ValueError("String creature must contain two integers") from exc
        # Fallback: try literal eval
        try:
            evaluated = ast.literal_eval(creature)
            return _as_pair(evaluated)
        except Exception as exc:
            raise ValueError("Unable to parse creature string") from exc

    raise ValueError(f"Unsupported creature type: {type(creature)}")


def battle(p1: List[Any], p2: List[Any]) -> dict:
    """Return the surviving creatures for each player."""
    survivors1: List[List[int]] = []
    survivors2: List[List[int]] = []

    len1, len2 = len(p1), len(p2)
    max_len = max(len1, len2)

    for i in range(max_len):
        c1_raw = p1[i] if i < len1 else None
        c2_raw = p2[i] if i < len2 else None

        if c1_raw is not None and c2_raw is not None:
            p1_power, p1_tough = _as_pair(c1_raw)
            p2_power, p2_tough = _as_pair(c2_raw)

            # Simultaneous damage
            if p2_power < p1_tough:
                survivors1.append([p1_power, p1_tough])
            if p1_power < p2_tough:
                survivors2.append([p2_power, p2_tough])

        elif c1_raw is not None:
            p1_power, p1_tough = _as_pair(c1_raw)
            survivors1.append([p1_power, p1_tough])

        elif c2_raw is not None:
            p2_power, p2_tough = _as_pair(c2_raw)
            survivors2.append([p2_power, p2_tough])

    return {"player1": survivors1, "player2": survivors2}


def parse_line(line: str) -> Any:
    """
    Convert a line of input into a Python object.
    Accepts JSON or Python literal representations.
    Returns the evaluated object (list, dict, etc.) or an empty list on failure.
    """
    line = line.strip()
    if not line:
        return []

    # Try Python literal first
    try:
        result = ast.literal_eval(line)
    except Exception:
        # Fallback to JSON
        try:
            result = json.loads(line)
        except Exception:
            return []

    return result


def main() -> None:
    data = sys.stdin.read().splitlines()
    # The kata supplies exactly two lines: one for each player's creatures.
    # If a line contains a dict with keys 'player1'/'player2', extract them.
    first = parse_line(data[0]) if len(data) > 0 else []
    second = parse_line(data[1]) if len(data) > 1 else []

    # Support the alternative format: a single JSON object with both players.
    if isinstance(first, dict) and "player1" in first and "player2" in first:
        p1 = first["player1"]
        p2 = first["player2"]
    else:
        p1 = first
        p2 = second

    result = battle(p1, p2)
    print(json.dumps(result))


if __name__ == "__main__":
    main()

def transform(s: str) -> str:
    vowels = {'a', 'e', 'i', 'o', 'u'}
    special = {'c', 'o', 'd', 'e'}
    special_shift = {'c': 1, 'o': 1, 'd': 3, 'e': 4}
    ALPH = 26
    res = []
    for ch in s:
        orig = ch
        if ch in special:
            delta = -special_shift[ch]
        elif ch in vowels:
            delta = -5
        else:
            delta = 9
        idx = ord(ch) - ord('a')
        new_idx = (idx + delta) % ALPH
        new_ch = chr(new_idx + ord('a'))
        if new_ch in special and new_ch != orig:
            new_ch = orig
        res.append(new_ch)
    return ''.join(res)


