def tiyFizzBuzz(s: str) -> str:
    upper_vowels = {'A', 'E', 'I', 'O', 'U'}
    lower_vowels = {'a', 'e', 'i', 'o', 'u'}

    parts = []
    for ch in s:
        if 'A' <= ch <= 'Z':                     # upper‑case ASCII
            if ch in upper_vowels:
                parts.append("Iron Yard")
            else:
                parts.append("Iron")
        elif 'a' <= ch <= 'z':                   # lower‑case ASCII
            if ch in lower_vowels:
                parts.append("Yard")
            else:
                parts.append(ch)                 # lower‑case consonant
        else:
            parts.append(ch)                     # non‑alphabetic
    return ''.join(parts)


