VOWELS = set('aeiou')

def alternate_lowest(s: str) -> str:
    vowels = []
    consonants = []
    for ch in s:
        if ch in VOWELS:
            vowels.append(ch)
        else:
            consonants.append(ch)

    vowels.sort()
    consonants.sort()

    v = len(vowels)
    c = len(consonants)

    if abs(v - c) > 1:
        return "failed"

    # decide which type starts
    if v == c:
        next_type = 'vowel'          # forced by problem statement
    elif v > c:
        next_type = 'vowel'
    else:
        next_type = 'consonant'

    i_v = i_c = 0
    result = []

    for _ in range(len(s)):
        if next_type == 'vowel':
            if i_v >= v:
                return "failed"
            result.append(vowels[i_v])
            i_v += 1
            next_type = 'consonant'
        else:
            if i_c >= c:
                return "failed"
            result.append(consonants[i_c])
            i_c += 1
            next_type = 'vowel'

    return ''.join(result)


