def green(n: int) -> str:
    """
    Return the n‑th green (automorphic) number as a decimal string.
    1‑based indexing: green(1) == "1".
    """
    if n == 1:
        return "1"

    # List of already produced green numbers (kept in increasing order)
    result = [1]

    # The two families start with the one‑digit numbers 5 and 6
    candidates = {5, 6}
    seen = {1, 5, 6}

    while len(result) < n:
        # The smallest candidate is the next green number in the sequence
        x = min(candidates)
        candidates.remove(x)
        result.append(x)

        # ---- generate the next longer number belonging to the same family ----
        k = len(str(x))          # current number of digits
        base = 10 ** k           # 10^k
        mod = base * 10          # 10^{k+1}

        for d in range(10):
            y = d * base + x     # candidate with one extra most‑significant digit
            if (y * y) % mod == y:
                if y not in seen:
                    candidates.add(y)
                    seen.add(y)
                break            # exactly one digit works (proved in the analysis)

    return str(result[n - 1])

