MOD = 100_000_000  # 10^8, keep only the last 8 digits


def countSubsequences(needle: str, haystack: str) -> int:
    if not needle:
        return 1
    if not haystack:
        return 0

    n = len(needle)
    dp = [0] * (n + 1)
    dp[0] = 1  # empty prefix

    for c in haystack:
        # iterate backwards so dp[i-1] is still the value from the previous step
        for i in range(n, 0, -1):
            if c == needle[i - 1]:
                dp[i] = (dp[i] + dp[i - 1]) % MOD

    return dp[n] % MOD


