import ast

def count_change(target, coins):
    """Return the number of unordered ways to make `target` using unlimited
    coins from `coins`."""
    if target < 0:
        raise ValueError("target must be non‑negative")
    if target == 0:
        return 1                     # one way: use no coins

    # Keep only positive, unique denominations
    clean = sorted({c for c in coins if c > 0})
    if not clean:
        return 0

    dp = [0] * (target + 1)
    dp[0] = 1

    for coin in clean:
        for amt in range(coin, target + 1):
            dp[amt] += dp[amt - coin]

    return dp[target]


def parse_coins(line):
    """
    Convert a line describing coin denominations into a list of positive ints.
    Accepts formats like "[1,2,3]", "(1 2 3)", "1 2 3", "1,2,3".
    """
    if not line:
        return []
    line = line.strip()
    # Try to evaluate as a Python literal (list/tuple)
    if line and line[0] in ('[', '('):
        try:
            parsed = ast.literal_eval(line)
            return [int(x) for x in parsed if int(x) > 0]
        except Exception:
            pass
    # Fallback: split on commas and whitespace
    parts = line.replace(',', ' ').split()
    result = []
    for p in parts:
        try:
            val = int(p)
            if val > 0:
                result.append(val)
        except ValueError:
            continue
    return result


