def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])

    if n < 2:
        print(0)
        return

    # ---------- linear sieve for smallest prime factor ----------
    spf = [0] * (n + 1)
    primes = []
    for i in range(2, n + 1):
        if spf[i] == 0:
            spf[i] = i
            primes.append(i)
        for p in primes:
            if p > spf[i] or i * p > n:
                break
            spf[i * p] = p

    # buckets keyed by smallest odd prime factor
    buckets = dict()          # prime -> list of numbers
    even_pool = []            # numbers that are pure powers of two

    for x in range(2, n + 1):
        if x % 2 == 0:
            # strip all factors 2
            y = x
            while y % 2 == 0:
                y //= 2
            if y == 1:                 # pure power of two
                even_pool.append(x)
                continue
            p = spf[y]                 # smallest odd prime divisor of the odd part
        else:
            p = spf[x]                 # x is odd, spf[x] is odd
        buckets.setdefault(p, []).append(x)

    pairs = []

    # ---------- process each bucket ----------
    for p, lst in buckets.items():
        # If the bucket size is odd, try to move an even element to the global pool
        if len(lst) % 2 == 1:
            even_idx = -1
            for i, val in enumerate(lst):
                if val % 2 == 0:
                    even_idx = i
                    break
            if even_idx != -1:
                even_pool.append(lst.pop(even_idx))
        # Pair the remaining numbers; ignore a possible single leftover element
        limit = len(lst) - (len(lst) % 2)   # largest even number ≤ len(lst)
        for i in range(0, limit, 2):
            a, b = lst[i], lst[i + 1]
            pairs.append((a, b))

    # ---------- pair the remaining even numbers (powers of two + evens moved) ----------
    for i in range(0, len(even_pool) - 1, 2):
        a, b = even_pool[i], even_pool[i + 1]
        pairs.append((a, b))

    # ---------- output ----------
    out_lines = [str(len(pairs))]
    out_lines += [f"{a} {b}" for a, b in pairs]
    sys.stdout.write("\n".join(out_lines))

