def solve() -> None:
    data = list(map(int, sys.stdin.read().split()))
    if not data:
        return
    it = iter(data)
    n = next(it)
    d = next(it)

    a = [0] * (n + 1)          # 1‑based, a[1]=a[n]=0
    for i in range(2, n):
        a[i] = next(it)

    x = [0] * (n + 1)
    y = [0] * (n + 1)
    for i in range(1, n + 1):
        x[i] = next(it)
        y[i] = next(it)

    # pre‑compute travelling costs
    cost = [[0] * (n + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        xi, yi = x[i], y[i]
        for j in range(1, n + 1):
            cost[i][j] = d * (abs(xi - x[j]) + abs(yi - y[j]))

    upper = cost[1][n]   # direct move is always possible

    def feasible(M: int) -> bool:
        """return True iff with initial time M we can reach station n"""
        best = [-1] * (n + 1)
        best[1] = M
        heap = [(-M, 1)]          # max‑heap via negative values
        while heap:
            cur_neg, v = heapq.heappop(heap)
            cur = -cur_neg
            if cur != best[v]:
                continue          # outdated entry
            for to in range(1, n + 1):
                if to == v:
                    continue
                need = cost[v][to]
                if cur < need:
                    continue
                nxt = cur - need + a[to]
                if nxt > best[to]:
                    best[to] = nxt
                    heapq.heappush(heap, (-nxt, to))
        return best[n] != -1

    lo, hi = 0, upper
    while lo < hi:
        mid = (lo + hi) // 2
        if feasible(mid):
            hi = mid
        else:
            lo = mid + 1

    print(lo)


