from collections import deque, defaultdict

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    m = int(next(it))
    a = int(next(it))
    b = int(next(it))

    # adjacency lists for a‑edges and b‑edges
    a_adj = [[] for _ in range(n + 1)]
    b_adj = [[] for _ in range(n + 1)]

    edges = []
    for _ in range(m):
        u = int(next(it))
        v = int(next(it))
        w = int(next(it))
        edges.append((u, v, w))
        if w == a:
            a_adj[u].append(v)
            a_adj[v].append(u)
        else:               # w == b
            b_adj[u].append(v)
            b_adj[v].append(u)

    # ---------- DSU for a‑components ----------
    parent = list(range(n + 1))

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x, y):
        rx, ry = find(x), find(y)
        if rx != ry:
            parent[ry] = rx

    for u, v, w in edges:
        if w == a:
            union(u, v)

    comp = [0] * (n + 1)
    comp_id = {}
    cid = 0
    for v in range(1, n + 1):
        r = find(v)
        if r not in comp_id:
            cid += 1
            comp_id[r] = cid
        comp[v] = comp_id[r]

    comp_of_one = comp[1]

    # ---------- distances using only a‑edges ----------
    INF = 10 ** 9
    da = [INF] * (n + 1)
    dq = deque([1])
    da[1] = 0
    while dq:
        u = dq.popleft()
        for v in a_adj[u]:
            if da[v] == INF:
                da[v] = da[u] + 1
                dq.append(v)

    # ---------- border vertices (incident to a b‑edge) ----------
    is_border = [False] * (n + 1)
    for u in range(1, n + 1):
        if b_adj[u]:
            is_border[u] = True

    # multi‑source BFS on a‑edges to compute distance to nearest border vertex
    borderDist = [INF] * (n + 1)
    dq = deque()
    for v in range(1, n + 1):
        if is_border[v]:
            borderDist[v] = 0
            dq.append(v)

    while dq:
        u = dq.popleft()
        for v in a_adj[u]:
            if borderDist[v] == INF:
                borderDist[v] = borderDist[u] + 1
                dq.append(v)

    # ---------- component graph built from b‑edges ----------
    comp_adj = defaultdict(set)
    for u, v, w in edges:
        if w == b:
            cu, cv = comp[u], comp[v]
            if cu != cv:
                comp_adj[cu].add(cv)
                comp_adj[cv].add(cu)

    # BFS on component graph to get number of b‑edges between components
    dbComp = {c: INF for c in range(1, cid + 1)}
    dq = deque([comp_of_one])
    dbComp[comp_of_one] = 0
    while dq:
        c = dq.popleft()
        for nb in comp_adj[c]:
            if dbComp[nb] == INF:
                dbComp[nb] = dbComp[c] + 1
                dq.append(nb)

    # ---------- compute answers ----------
    out = []
    for v in range(1, n + 1):
        if comp[v] == comp_of_one:
            # same a‑component: we can stay inside it
            ans = da[v] * a
        else:
            # need to cross components
            # borderDist[1] and borderDist[v] are guaranteed finite because the whole graph is connected
            ans = (borderDist[1] + borderDist[v]) * a + dbComp[comp[v]] * b
        out.append(str(ans))

    sys.stdout.write(' '.join(out))

