def canonical(word: str) -> str:
    # 1. expand every 'u' to "oo"
    expanded = []
    for ch in word:
        if ch == 'u':
            expanded.append('o')
            expanded.append('o')
        else:
            expanded.append(ch)

    # 2. delete preceding 'k' before each 'h' (kh -> h)
    stack = []
    for ch in expanded:
        if ch == 'h':
            while stack and stack[-1] == 'k':
                stack.pop()
            stack.append('h')
        else:
            stack.append(ch)

    return ''.join(stack)


