import sys
from functools import lru_cache

sys.setrecursionlimit(10000)


def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    edges = []
    adj = [[] for _ in range(n)]
    for _ in range(n - 1):
        u = int(next(it)) - 1
        v = int(next(it)) - 1
        edges.append((u, v))
        adj[u].append(v)
        adj[v].append(u)

    # -------------------------------------------------
    # component masks for directed edges:
    # comp[a][b] = vertices reachable from a without using edge {a,b}
    # -------------------------------------------------
    comp = [[0] * n for _ in range(n)]

    def dfs(start: int, forbid: int) -> int:
        """bitmask of vertices reachable from `start` without the edge start‑forbid."""
        stack = [start]
        visited = 0
        while stack:
            v = stack.pop()
            if (visited >> v) & 1:
                continue
            visited |= 1 << v
            for nb in adj[v]:
                # skip the forbidden undirected edge
                if (v == start and nb == forbid) or (v == forbid and nb == start):
                    continue
                stack.append(nb)
        return visited

    for u, v in edges:
        comp[u][v] = dfs(u, v)
        comp[v][u] = dfs(v, u)

    # -------------------------------------------------
    # DP on masks (connected vertex sets)
    # -------------------------------------------------
    @lru_cache(maxsize=None)
    def dp(mask: int):
        """Return a tuple of length n.
           tuple[i] = probability that i wins inside the sub‑tree described by mask."""
        size = mask.bit_count()
        if size == 1:
            # only one vertex – it wins with probability 1
            v = (mask & -mask).bit_length() - 1
            prob = [0.0] * n
            prob[v] = 1.0
            return tuple(prob)

        factor = 0.5 / (size - 1)
        prob = [0.0] * n

        for a, b in edges:
            if not ((mask >> a) & 1) or not ((mask >> b) & 1):
                continue

            # component that contains a after removing edge a‑b
            side_a = comp[a][b] & mask
            if side_a:
                vec_a = dp(side_a)
                for i in range(n):
                    if (side_a >> i) & 1:
                        prob[i] += factor * vec_a[i]

            # component that contains b
            side_b = comp[b][a] & mask
            if side_b:
                vec_b = dp(side_b)
                for i in range(n):
                    if (side_b >> i) & 1:
                        prob[i] += factor * vec_b[i]

        return tuple(prob)

    full_mask = (1 << n) - 1
    answer = dp(full_mask)

    out = "\n".join(f"{answer[i]:.10f}" for i in range(n))
    sys.stdout.write(out)


